                LOG.info("Found stray log dir {}: the current replica assignment {} does not contain the local brokerId {}.",
                        log, replicas.stream().map(String::valueOf).collect(Collectors.joining(", ", "[", "]")), brokerId);
                return true;
            } else {
                return false;
            }
        }
    }
}

